1	import { describe, it, expect } from "vitest";
2	import { render, screen } from "@testing-library/react";
3	import { ProbabilityBar } from "@/components/ui/ProbabilityBar";
4	
5	const OUTCOME_COLORS = [
6	  "#22c55e", "#ef4444", "#3b82f6", "#eab308", "#a855f7",
7	  "#ec4899", "#14b8a6", "#f97316",
8	];
9	
10	describe("ProbabilityBar", () => {
11	  it("renders with probability 0 — both outcomes at 0", () => {
12	    const outcomes = [
13	      { id: "yes", name: "Yes" },
14	      { id: "no", name: "No" },
15	    ];
16	    const { container } = render(
17	      <ProbabilityBar outcomes={outcomes} marginals={{ yes: 0, no: 0 }} />,
18	    );
19	
20	    // Title attributes show 0.0%
21	    expect(screen.getByTitle("Yes: 0.0%")).toBeInTheDocument();
22	    expect(screen.getByTitle("No: 0.0%")).toBeInTheDocument();
23	
24	    // Visible span text shows 0.0%
25	    expect(screen.getByText("Yes 0.0%")).toBeInTheDocument();
26	    expect(screen.getByText("No 0.0%")).toBeInTheDocument();
27	
28	    // Bar segments have 0% width and minWidth 0
29	    const bars = container.querySelectorAll("[title]");
30	    for (const bar of bars) {
31	      expect((bar as HTMLElement).style.width).toBe("0%");
32	      expect((bar as HTMLElement).style.minWidth).toBe("0");
33	    }
34	  });
35	
36	  it("renders with probability 0.5 — both outcomes at 0.5", () => {
37	    const outcomes = [
38	      { id: "yes", name: "Yes" },
39	      { id: "no", name: "No" },
40	    ];
41	    render(
42	      <ProbabilityBar outcomes={outcomes} marginals={{ yes: 0.5, no: 0.5 }} />,
43	    );
44	
45	    // Title attributes show 50.0%
46	    expect(screen.getByTitle("Yes: 50.0%")).toBeInTheDocument();
47	    expect(screen.getByTitle("No: 50.0%")).toBeInTheDocument();
48	
49	    // Visible span text shows 50.0%
50	    expect(screen.getByText("Yes 50.0%")).toBeInTheDocument();
51	    expect(screen.getByText("No 50.0%")).toBeInTheDocument();
52	
53	    // Bar segments have 50% width and minWidth 2 (since p > 0)
54	    const yesBar = screen.getByTitle("Yes: 50.0%");
55	    const noBar = screen.getByTitle("No: 50.0%");
56	    expect(yesBar.style.width).toBe("50%");
57	    expect(yesBar.style.minWidth).toBe("2px");
58	    expect(noBar.style.width).toBe("50%");
59	    expect(noBar.style.minWidth).toBe("2px");
60	  });
61	
62	  it("renders with probability 1 — one outcome at 1, other at 0", () => {
63	    const outcomes = [
64	      { id: "yes", name: "Yes" },
65	      { id: "no", name: "No" },
66	    ];
67	    render(
68	      <ProbabilityBar outcomes={outcomes} marginals={{ yes: 1, no: 0 }} />,
69	    );
70	
71	    // Title attributes
72	    expect(screen.getByTitle("Yes: 100.0%")).toBeInTheDocument();
73	    expect(screen.getByTitle("No: 0.0%")).toBeInTheDocument();
74	
75	    // Visible span text
76	    expect(screen.getByText("Yes 100.0%")).toBeInTheDocument();
77	    expect(screen.getByText("No 0.0%")).toBeInTheDocument();
78	
79	    // Bar widths
80	    const yesBar = screen.getByTitle("Yes: 100.0%");
81	    const noBar = screen.getByTitle("No: 0.0%");
82	    expect(yesBar.style.width).toBe("100%");
83	    expect(noBar.style.width).toBe("0%");
84	    expect(yesBar.style.minWidth).toBe("2px");
85	    expect(noBar.style.minWidth).toBe("0");
86	  });
87	
88	  it("displays percentage in both title attributes and visible span labels", () => {
89	    const outcomes = [
90	      { id: "a", name: "Alpha" },
91	      { id: "b", name: "Beta" },
92	    ];
93	    const marginals = { a: 0.73, b: 0.27 };
94	    render(<ProbabilityBar outcomes={outcomes} marginals={marginals} />);
95	
96	    // Title attributes (on the bar segments)
